GameReward = {}

function GameReward:sendNotificationResult(player, reward)
    if reward and reward.IsNotification and #reward.NotificationContent ~= 0 then
        local data = {
            message = reward.NotificationContent,
            top = true
        }
        if #reward.NotificationParams ~= 0 then
            data.params = player:getDisplayName() ..  "#" .. reward.NotificationParams
        else
            data.params = player:getDisplayName()
        end
        WebService:SendMsg(nil, json.encode(data), 4, "game", GameMatch.gameType)
    end
    return reward.Id
end

function GameReward:onPlayerGetReward(player, reward, time)
    if not reward then
        return false
    end
    local delay = time or 0
    local hasGet
    if reward.RewardType == Define.RewardType.GunChip then
        hasGet = self:onPlayerRewardGunChip(player, reward.RewardId, reward.Count)
        player.taskController:packingProgressData(player, Define.TaskType.GrowUp.GainCoin, GameMatch.gameType, Define.Money.CHIP, reward.Count)
    end
    if reward.RewardType == Define.RewardType.Gun then
        hasGet = self:onPlayerRewardGun(player, reward.RewardId, reward.Count)
    end
    if reward.RewardType == Define.RewardType.PropChip then
        hasGet = self:onPlayerRewardPropChip(player, reward.RewardId, reward.Count)
        player.taskController:packingProgressData(player, Define.TaskType.GrowUp.GainCoin, GameMatch.gameType, Define.Money.CHIP, reward.Count)
    end
    if reward.RewardType == Define.RewardType.Prop then
        hasGet = self:onPlayerRewardProp(player, reward.RewardId, reward.Count)
    end
    if reward.RewardType == Define.RewardType.Money then
        LuaTimer:schedule(function(userId, count)
            local c_player = PlayerManager:getPlayerByUserId(userId)
            if not c_player then
                return
            end
            c_player:addCurrency(count or 0)
        end, delay * 1000, nil, player.userId, reward.Count)
        player.taskController:packingProgressData(player, Define.TaskType.GrowUp.GainCoin, GameMatch.gameType, Define.Money.MONEY, reward.Count)
    end
    if reward.RewardType == Define.RewardType.Key then
        player.yaoshi = player.yaoshi + reward.Count
        player:syncHallInfo()
        player.taskController:packingProgressData(player, Define.TaskType.GrowUp.GainCoin, GameMatch.gameType, Define.Money.KEY, reward.Count)
    end
    if reward.RewardType == Define.RewardType.Vip then
        self:onPlayerRewardVip(player, reward.Time)
    end
    if reward.RewardType == Define.RewardType.Exp then
        self:onPlayerAddExp(player, reward.Count)
    end
    if reward.RewardType == Define.RewardType.Chest then
        self:addPlayerLotteryChest(player, reward.RewardId, reward.Count)
    end
    if reward.RewardType == Define.RewardType.Ticket then
        self:addPlayerTicket(player, reward.RewardId, reward.Count)
    end
    if hasGet then
        local redress_reward = RewardConfig:getRewardById(reward.RedressRewardId)
        if redress_reward then
            return self:onPlayerGetReward(player, redress_reward)
        else
            print("Do not have Reward by Id(" .. reward.RedressRewardId .. ")")
        end
        return
    end
    self:sendNotificationResult(player, reward)
    return reward.Id
end

function GameReward:onPlayerRewardGunChip(player, gunId, count)
    if count == 0 then
        return
    end
    local player_gun
    for _, gun in pairs(player.guns) do
        if gun.Id == gunId then
            player_gun = gun
        end
    end
    if not player_gun then
        player_gun = {
            Id = gunId,
            Level = 1,
            Status = GameGunStore.Status.LOCK,
            Chip = 0,
            UpgradeTime = 0,
        }
        table.insert(player.guns, player_gun)
    end
    player_gun.Chip = player_gun.Chip + count
    local data = {}
    table.insert(data, {
        Id = player_gun.Id,
        Chip = player_gun.Chip,
    })
    GameGunStore:sendUpdateStoreGunData(player, data)
end

function GameReward:onPlayerRewardGun(player, gunId, count)
    local player_gun
    for _, gun in pairs(player.guns) do
        if gun.Id == gunId then
            player_gun = gun
        end
    end
    if not player_gun then
        player_gun = {
            Id = gunId,
            Level = 1,
            Status = GameGunStore.Status.LOCK,
            Chip = 0,
            UpgradeTime = 0,
        }
        table.insert(player.guns, player_gun)
    end
    if player_gun.Status ~= GameGunStore.Status.HAS_GET and player_gun.Status ~= GameGunStore.Status.HAS_USE then
        player_gun.Status = GameGunStore.Status.HAS_GET
        local data = {}
        table.insert(data, {
            Id = player_gun.Id,
            Status = player_gun.Status,
        })
        GameGunStore:sendUpdateStoreGunData(player, data)
    else
        return true
    end
end

function GameReward:onPlayerRewardPropChip(player, propId, count)
    if count == 0 then
        return
    end
