function GameReward:onPlayerRewardVip(player, time)
    if time == 0 then
        return
    end
    local isVip = player:isGameVip()
    if player.vip_time <= os.time() then
        player.vip_time = os.time()
    end
    player.vip_time = player.vip_time + time
    if not isVip then
        player:setShowName(player:buildShowName())
    end
    player:syncHallInfo()
end

function GameReward:onPlayerAddExp(player, count)
    player:addExp(count)
end

function GameReward:addPlayerLotteryChest(player, id, count)
    local data = {}
    for _, chest in pairs(player.chests) do
        if chest.Id == id then
            chest.HasNum = chest.HasNum + count
            table.insert(data, {
                Id = chest.Id,
                HasNum = chest.HasNum
            })
        end
    end
    GameChestLottery:sendUpdateLotteryChestData(player, data)
end

function GameReward:addPlayerTicket(player, type, count)
    player.ticketManager:addTicket(type, count)
end

return GameReward